class Solution:
    def minAbsoluteDifference(self, nums):
        n = len(nums)
        best = None
        for i in range(n):
            for j in range(n):
                if nums[i] == 1 and nums[j] == 2:
                    d = abs(i - j)
                    best = d if best is None else min(best, d)
        return best if best is not None else -1

