class Solution:
    def minAbsoluteDifference(self, nums):
        last1 = -1
        last2 = -1
        best = None
        for k, v in enumerate(nums):
            if v == 1:
                if last2 != -1:
                    d = abs(k - last2)
                    best = d if best is None else min(best, d)
                last1 = k
            elif v == 2:
                if last1 != -1:
                    d = abs(k - last1)
                    best = d if best is None else min(best, d)
                last2 = k
        return best if best is not None else -1

