var minAbsoluteDifference = function(nums) {
    let last1 = -1, last2 = -1, best = -1;
    for (let k = 0; k < nums.length; k++) {
        const v = nums[k];
        if (v === 1) {
            if (last2 !== -1) {
                const d = Math.abs(k - last2);
                best = best === -1 ? d : Math.min(best, d);
            }
            last1 = k;
        } else if (v === 2) {
            if (last1 !== -1) {
                const d = Math.abs(k - last1);
                best = best === -1 ? d : Math.min(best, d);
            }
            last2 = k;
        }
    }
    return best;
};
